//     final tsconfig = tsconfigFromJson(jsonString);

import 'dart:convert';

Tsconfig tsconfigFromJson(String str) => Tsconfig.fromJson(json.decode(str));

String tsconfigToJson(Tsconfig data) => json.encode(data.toJson());

class Tsconfig {
    String schema;
    String display;
    CompilerOptions compilerOptions;

    Tsconfig({
        required this.schema,
        required this.display,
        required this.compilerOptions,
    });

    factory Tsconfig.fromJson(Map<String, dynamic> json) => Tsconfig(
        schema: json["\u0024schema"],
        display: json["display"],
        compilerOptions: CompilerOptions.fromJson(json["compilerOptions"]),
    );

    Map<String, dynamic> toJson() => {
        "\u0024schema": schema,
        "display": display,
        "compilerOptions": compilerOptions.toJson(),
    };
}

class CompilerOptions {
    List<String> lib;
    String module;
    String target;
    bool strict;
    bool esModuleInterop;
    bool skipLibCheck;
    bool forceConsistentCasingInFileNames;
    String moduleResolution;

    CompilerOptions({
        required this.lib,
        required this.module,
        required this.target,
        required this.strict,
        required this.esModuleInterop,
        required this.skipLibCheck,
        required this.forceConsistentCasingInFileNames,
        required this.moduleResolution,
    });

    factory CompilerOptions.fromJson(Map<String, dynamic> json) => CompilerOptions(
        lib: List<String>.from(json["lib"].map((x) => x)),
        module: json["module"],
        target: json["target"],
        strict: json["strict"],
        esModuleInterop: json["esModuleInterop"],
        skipLibCheck: json["skipLibCheck"],
        forceConsistentCasingInFileNames: json["forceConsistentCasingInFileNames"],
        moduleResolution: json["moduleResolution"],
    );

    Map<String, dynamic> toJson() => {
        "lib": List<dynamic>.from(lib.map((x) => x)),
        "module": module,
        "target": target,
        "strict": strict,
        "esModuleInterop": esModuleInterop,
        "skipLibCheck": skipLibCheck,
        "forceConsistentCasingInFileNames": forceConsistentCasingInFileNames,
        "moduleResolution": moduleResolution,
    };
}
